// shadcn
import { Button } from "@/components/ui/button";

// constants
const faqs = [
  {
    question: "Why Must I Make Payment Immediately At Checkout?",
    answer:
      "Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  },
  {
    question: "What Happens if There's Been A Delivery Mishap To My Order?",
    answer:
      "Because you are important to us, we want to know what you think about the products. As an added value, every time you rate the products you earn points."
  },
  {
    question:
      "How Long Will It Take For My Order To Arrive After I Make Payment?",
    answer:
      "Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  }
];

//  ------------------------------ | FAQ - 9 | ------------------------------  //

export default function Faq9() {
  return (
    <section className="bg-primary py-20 md:py-28 text-white">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-6 items-center">
          {/* Left Column: Heading & Button */}
          <div className="col-span-12 md:col-span-5 max-w-xs">
            <h2 className="mb-6 text-white">
              Got Questions ? We’ve Got Answers
            </h2>
            <p className="text-white/80 mb-8">
              This is a big one and i consider it one of the most important
              things for a designer to get right.
            </p>
            <Button
              size="lg"
              className="bg-yellow-500 text-white hover:bg-yellow-400"
            >
              Get Started
            </Button>
          </div>

          {/* Right Column: FAQ List */}
          <div className="col-span-12 md:col-span-7 max-w-lg">
            <div className="flex flex-col gap-10">
              {faqs.map((item, index) => (
                <div key={index} className="flex flex-col gap-4">
                  <h5 className="text-white">{item.question}</h5>
                  <div className="h-0.5 w-full bg-yellow-500" />
                  <p className="text-white/70 text-md">{item.answer}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
